import { ToggleGroup as ToggleGroupPrimitive } from '@base-ui/react/toggle-group';
import {
  createContext,
  forwardRef,
  useContext,
  useMemo,
  type ComponentProps,
  type ComponentRef,
} from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import { Toggle } from '../toggle';
import styles from './ToggleGroup.module.css';

type ToggleVariant = ComponentProps<typeof Toggle>['variant'];
type ToggleSize = ComponentProps<typeof Toggle>['size'];

const ToggleGroupContext = createContext<{
  variant: ToggleVariant;
  size: ToggleSize;
}>({
  variant: 'default',
  size: 'md',
});

const ToggleGroup = forwardRef<
  ComponentRef<typeof ToggleGroupPrimitive>,
  ToggleGroupPrimitive.Props & {
    variant?: ToggleVariant;
    size?: ToggleSize;
  }
>(function ToggleGroup({ className, variant = 'default', size = 'md', ...props }, ref) {
  const contextValue = useMemo(() => ({ variant, size }), [size, variant]);

  return (
    <ToggleGroupContext.Provider value={contextValue}>
      <ToggleGroupPrimitive
        ref={ref}
        data-slot="toggle-group-root"
        data-variant={variant}
        data-size={size}
        className={mergeClassName(className, styles.root)}
        {...props}
      />
    </ToggleGroupContext.Provider>
  );
});

const ToggleGroupItem = forwardRef<ComponentRef<typeof Toggle>, ComponentProps<typeof Toggle>>(
  function ToggleGroupItem({ className, variant, size, ...props }, ref) {
    const inherited = useContext(ToggleGroupContext);

    return (
      <Toggle
        ref={ref}
        data-slot="toggle-group-item"
        variant={variant ?? inherited.variant}
        size={size ?? inherited.size}
        className={mergeClassName(className, styles.item)}
        {...props}
      />
    );
  },
);

export { ToggleGroup, ToggleGroupItem };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    gap: var(--toggle-group-gap, var(--border-width-sm));
    padding: var(--toggle-group-padding, 0.125rem);
    border: var(--toggle-group-border-width, var(--border-width-sm)) solid
      var(--toggle-group-border-color, var(--color-border));
    border-radius: var(--toggle-group-radius, var(--radius-lg));
    background-color: var(--toggle-group-bg, var(--color-muted));
    color: var(--toggle-group-color, var(--color-foreground));
  }

  .root[data-orientation='vertical'] {
    flex-direction: column;
    align-items: stretch;
  }

  .root[data-variant='ghost'] {
    --toggle-group-bg: var(--toggle-group-ghost-bg, transparent);
    --toggle-group-border-color: var(--toggle-group-ghost-border-color, transparent);
    --toggle-group-padding: var(--toggle-group-ghost-padding, 0);
  }

  .root[data-variant='outline'] {
    --toggle-group-bg: var(--toggle-group-outline-bg, var(--color-background));
  }

  .item {
    flex: 0 0 auto;
    border-radius: var(--toggle-group-item-radius, var(--radius-md));
    --toggle-default-color: var(--toggle-group-color, var(--color-foreground));
    --toggle-ghost-color: var(--toggle-group-color, var(--color-foreground));
    --toggle-outline-color: var(--toggle-group-color, var(--color-foreground));
  }

  .root[data-orientation='vertical'] > .item {
    width: 100%;
    justify-content: flex-start;
  }
}
